#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

bool has_distinct_digits(int num) {
    char str[11];
    sprintf(str, "%d", num);
    int len = strlen(str);
    for (int i = 0; i < len; i++) {
        for (int j = i + 1; j < len; j++) {
            if (str[i] == str[j]) {
                return false;
            }
        }
    }
    return true;
}

int main() {
    int n;
    scanf("%d", &n);
    n++;
    while (!has_distinct_digits(n)) {
        n++;
    }
    printf("%d\n", n);
    return 0;
}
